            update request_action
			set payload = jsonb_set(payload, '{payload, sicCode}', jsonb_build_array(payload -> 'payload' -> 'sicCode'), false)
			where payload->'payload' ?? 'sicCode';

            update request_action
			set payload = jsonb_set(payload, '{payload, sicCodes}', payload -> 'payload' -> 'sicCode') #- '{payload, sicCode}'
			where payload->'payload' ?? 'sicCode';

            update request
			set payload = jsonb_set(payload, '{reviewSectionsCompleted}', REPLACE((payload-> 'reviewSectionsCompleted')::TEXT, '"APPROVED"', '"ACCEPTED"')::JSONB)
			where jsonb_path_exists(payload-> 'reviewSectionsCompleted', '$.** ? (@ == "APPROVED")');

            update request_task
			set payload = jsonb_set(payload, '{reviewSectionsCompleted}', REPLACE((payload-> 'reviewSectionsCompleted')::TEXT, '"APPROVED"', '"ACCEPTED"')::JSONB)
			where jsonb_path_exists(payload-> 'reviewSectionsCompleted', '$.** ? (@ == "APPROVED")');

            update request_action
			set payload = jsonb_set(payload, '{reviewSectionsCompleted}', REPLACE((payload-> 'reviewSectionsCompleted')::TEXT, '"APPROVED"', '"ACCEPTED"')::JSONB)
			where jsonb_path_exists(payload-> 'reviewSectionsCompleted', '$.** ? (@ == "APPROVED")');

